module top_module(
  input clk,
  input [7:0] obf_a,
  input [7:0] b,
  input [2:0] op,
  output reg [7:0] res
);always @(posedge clk) begin
  case(op)
    3'b000: res <= obf_a + b;
    3'b001: res <= obf_a - b;
    3'b010: res <= obf_a & b;
    3'b011: res <= obf_a | b;
    3'b100: res <= obf_a ^ b;
    3'b101: res <= ~(obf_a & b);
    3'b110: res <= ~(obf_a | b);
    3'b111: res <= ~(obf_a ^ b);
  endcase
end

endmodule
